import app from 'flarum/forum/app';
import Hero from 'flarum/forum/components/Hero';
import Icon from 'flarum/common/components/Icon';
import ItemList from 'flarum/common/utils/ItemList';
export default class MessagesPageHero extends Hero {
  className() {
    return 'MessagesPageHero';
  }
  bodyItems() {
    const items = new ItemList();
    items.add('content', m("div", {
      className: "containerNarrow"
    }, this.contentItems().toArray()), 80);
    return items;
  }
  contentItems() {
    const items = new ItemList();
    items.add('title', m("h1", {
      className: "Hero-title"
    }, m(Icon, {
      name: "fas fa-envelope"
    }), " ", app.translator.trans('flarum-messages.forum.messages_page.hero.title')), 100);
    items.add('subtitle', m("div", {
      className: "Hero-subtitle"
    }, app.translator.trans('flarum-messages.forum.messages_page.hero.subtitle')), 90);
    return items;
  }
}
flarum.reg.add('flarum-messages', 'forum/components/MessagesPageHero', MessagesPageHero);